Data.data:
body {
  background: url("/images/background.png");
  background-repeat: no-repeat;
  background-attachment: fixed;
  background-size: cover;
  background-position: center;
}
.main-inner > .sub-menu,
.main-inner > .post-block,
.main-inner > .tabs-comment,
.main-inner > .comments,
.main-inner > .pagination {
  background: rgba(255,255,255,0.8);
}
body {
  font-size: 15px;
}
.sidebar {
  opacity: 0.85;
}
.header-inner {
  background: rgba(255,255,255,0.85);
}
.popup {
  opacity: 0.8;
}
.main-inner {
  background-color: rgba(255,255,255,0.85);
  padding: 0px 20px 20px 20px;
}
.category-all .category-list {
  list-style: none;
  padding-left: 0;
}
.category-all .category-list-item {
  margin: 0.35em 0;
}
.category-all .category-list-item .category-toggle {
  display: inline-block;
  width: 1.2em;
  margin-right: 0.35em;
  color: #666;
  cursor: pointer;
  user-select: none;
  transition: transform 0.2s ease;
}
.category-all .category-list-item.expanded > .category-toggle {
  transform: rotate(90deg);
}
.category-all .category-list-child {
  margin-left: 1.8em;
  display: none;
}
.category-all .category-list-item.expanded > .category-list-child {
  display: block;
}
.category-all .category-post-link::before {
  content: '📄 ';
  font-style: normal;
}
.category-all .category-post-link {
  font-size: 0.92em;
  color: #555;
}
